        "altitude": { "type": "number", "description": "Altitude in meters above mean sea level" }
      },
      "required": ["latitude", "longitude", "altitude"]
    },
    "heading": {
      "type": "number",
      "description": "Heading in degrees (0-360, true north)"
    },
    "velocity": {
      "type": "number",
      "description": "Ground speed in meters per second"
    },
