      "properties": {
        "temperature": { "type": "number", "description": "Avg °C" },
        "humidity": { "type": "number", "description": "Avg %" },
        "radiationExposure": { "type": "number", "description": "Cumulative rem" }
      }
    },
    "usageHours": { "type": "number" },
